&lt;p&gt;Hence, &lt;span class=&quot;katex&quot;&gt;&lt;span class=&quot;katex-mathml&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;mrow&amp;gt;&amp;lt;mi&amp;gt;&amp;lt;/mi&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-862-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;mrow&amp;gt;&amp;lt;mi&amp;gt;&amp;lt;/mi&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-61-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;/span&gt;
&lt;script id=&quot;MathJax-Element-61&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt;
&lt;/span&gt;&lt;/span&gt; &lt;script id=&quot;MathJax-Element-862&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt; &lt;/span&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;W&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; is not a subspace of &lt;span class=&quot;katex&quot;&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;V&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;. This statement is false.&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;C.&lt;/strong&gt; If u&amp;nbsp;= (1, 2), v = (-3, -5), then u and v are linearly independent&lt;/p&gt;

&lt;p&gt;To check for linear independence, solve &lt;span class=&quot;katex&quot;&gt;&lt;span class=&quot;katex-mathml&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;mrow&amp;gt;&amp;lt;msup&amp;gt;&amp;lt;mi&amp;gt;&amp;lt;/mi&amp;gt;&amp;lt;/msup&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-863-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;mrow&amp;gt;&amp;lt;msup&amp;gt;&amp;lt;mi&amp;gt;&amp;lt;/mi&amp;gt;&amp;lt;/msup&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-62-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;/span&gt;
&lt;script id=&quot;MathJax-Element-62&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt;
&lt;/span&gt;&lt;/span&gt; &lt;script id=&quot;MathJax-Element-863&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt; &lt;annotation encoding=&quot;application/x-tex&quot;&gt;&lt;/annotation&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span class=&quot;katex&quot;&gt;&lt;span class=&quot;katex-mathml&quot;&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt;&lt;/annotation&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;math-tex&quot;&gt;\(c_1 u + c_2 v = 0c_1​u+c_2v=0: \)&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;c&lt;sub&gt;1&lt;/sub&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mopen&quot;&gt;(&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;1&lt;/span&gt;&lt;span class=&quot;mpunct&quot;&gt;,&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;2&lt;/span&gt;&lt;span class=&quot;mclose&quot;&gt;)&lt;/span&gt;&lt;span class=&quot;mbin&quot;&gt;+&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;c&lt;sub&gt;2&lt;/sub&gt;&lt;/span&gt;&lt;span class=&quot;msupsub&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mopen&quot;&gt;(&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&amp;minus;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;3&lt;/span&gt;&lt;span class=&quot;mpunct&quot;&gt;,&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&amp;minus;&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;5&lt;/span&gt;&lt;span class=&quot;mclose&quot;&gt;)&amp;nbsp;&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mopen&quot;&gt;(&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;0&lt;/span&gt;&lt;span class=&quot;mpunct&quot;&gt;,&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;0&lt;/span&gt;&lt;span class=&quot;mclose&quot;&gt;)&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&amp;rArr;&amp;nbsp;&lt;span class=&quot;mord mathnormal&quot;&gt;c&lt;/span&gt;&lt;span class=&quot;msupsub&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;sub&gt;1&lt;/sub&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mbin&quot;&gt;&amp;minus;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;3&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;c&lt;sub&gt;2&lt;/sub&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;0&lt;/span&gt;&lt;span class=&quot;mpunct&quot;&gt;,&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;2&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;c&lt;sub&gt;1&lt;/sub&gt;&lt;/span&gt;&lt;span class=&quot;msupsub&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mbin&quot;&gt;&amp;minus;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;5&lt;/span&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;c&lt;sub&gt;2&lt;/sub&gt;&lt;/span&gt;&lt;span class=&quot;msupsub&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;0.&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr;&amp;nbsp;c&lt;/span&gt;&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span class=&quot;katex&quot;&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;msupsub&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;, then &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;c&lt;sub&gt;1&lt;/sub&gt;&lt;/span&gt;&lt;span class=&quot;katex&quot;&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;msupsub&quot;&gt;&lt;span class=&quot;vlist-t vlist-t2&quot;&gt;&lt;span class=&quot;vlist-r&quot;&gt;&lt;span class=&quot;vlist-s&quot;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;mrel&quot;&gt;=&lt;/span&gt;&lt;/span&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;.&lt;/p&gt;

&lt;p&gt;Hence, &lt;span class=&quot;katex&quot;&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;u&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; and &lt;span class=&quot;katex&quot;&gt;&lt;span class=&quot;katex-mathml&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;mrow&amp;gt;&amp;lt;mi&amp;gt;&amp;lt;/mi&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-864-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;mrow&amp;gt;&amp;lt;mi&amp;gt;&amp;lt;/mi&amp;gt;&amp;lt;/mrow&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-63-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;/span&gt;
&lt;script id=&quot;MathJax-Element-63&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt;
&lt;/span&gt;&lt;/span&gt; &lt;script id=&quot;MathJax-Element-864&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;&lt;/mi&gt;&lt;/mrow&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt; &lt;/span&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord mathnormal&quot;&gt;v&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; are linearly independent. This statement is true.&lt;/p&gt;

&lt;p&gt;To form a basis of&amp;nbsp;&lt;span class=&quot;katex&quot;&gt;&lt;span class=&quot;katex-mathml&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;annotation encoding=&amp;quot;application/x-tex&amp;quot;&amp;gt;      \mathbb{R}^3&amp;lt;/annotation&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-865-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;annotation encoding=&amp;quot;application/x-tex&amp;quot;&amp;gt;       \mathbb{R}^3&amp;lt;/annotation&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-64-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt; \mathbb{R}^3&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;/span&gt;
&lt;script id=&quot;MathJax-Element-64&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt; \mathbb{R}^3&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt;
&lt;/span&gt;&lt;/span&gt; &lt;script id=&quot;MathJax-Element-865&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt;\mathbb{R}^3&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt; &lt;/span&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord mathbb&quot;&gt;R&lt;sup&gt;3&lt;/sup&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;, the set must have three linearly independent vectors.&lt;/p&gt;

&lt;p&gt;Here, only two vectors are provided.&lt;/p&gt;

&lt;p&gt;Therefore, they cannot form a basis of &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span class=&quot;katex&quot; style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span class=&quot;katex-mathml&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;annotation encoding=&amp;quot;application/x-tex&amp;quot;&amp;gt;&amp;lt;/annotation&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-866-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;span class=&quot;MathJax&quot; data-mathml=&quot;&amp;lt;math xmlns=&amp;quot;http://www.w3.org/1998/Math/MathML&amp;quot;&amp;gt;&amp;lt;semantics&amp;gt;&amp;lt;annotation encoding=&amp;quot;application/x-tex&amp;quot;&amp;gt;&amp;lt;/annotation&amp;gt;&amp;lt;/semantics&amp;gt;&amp;lt;/math&amp;gt;&quot; id=&quot;MathJax-Element-65-Frame&quot; role=&quot;presentation&quot; style=&quot;position: relative;&quot; tabindex=&quot;0&quot;&gt;&lt;nobr aria-hidden=&quot;true&quot;&gt;&lt;/nobr&gt;&lt;span class=&quot;MJX_Assistive_MathML&quot; role=&quot;presentation&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;/span&gt;
&lt;script id=&quot;MathJax-Element-65&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt;
&lt;/span&gt;&lt;/span&gt; &lt;script id=&quot;MathJax-Element-866&quot; type=&quot;math/mml&quot;&gt;&lt;math xmlns=&quot;http://www.w3.org/1998/Math/MathML&quot;&gt;&lt;semantics&gt;&lt;annotation encoding=&quot;application/x-tex&quot;&gt;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/script&gt; &lt;/span&gt;&lt;span aria-hidden=&quot;true&quot; class=&quot;katex-html&quot;&gt;&lt;span class=&quot;base&quot;&gt;&lt;span class=&quot;mord&quot;&gt;&lt;span class=&quot;mord mathbb&quot;&gt;R&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;. This statement is false.&lt;/p&gt;

&lt;p&gt;Hence &lt;strong&gt;option 1&lt;/strong&gt; is correct.&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Concept:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;(i) Let f: A&amp;nbsp;&amp;rarr; B and g:B&amp;nbsp;&amp;rarr; C be two function such that g∘ f is one-one and onto i.e., bijective then f is one one and g is onto.&lt;/p&gt;

&lt;p&gt;(ii) Rank-nullity theorem: Let T: V&amp;nbsp;&amp;rarr; W be a linear transformation then rank(T) + nullity(T) = dim V&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Explanation:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;T&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;1&lt;/span&gt;&amp;nbsp;:&amp;nbsp;ℝ&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;n&lt;/span&gt;&amp;nbsp;&amp;rarr;&amp;nbsp;ℝ&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;m&lt;/span&gt;&amp;nbsp;and T&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;:&amp;nbsp;ℝ&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;m&lt;/span&gt;&amp;nbsp;&amp;rarr;&amp;nbsp;ℝ&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;n&lt;/span&gt;&amp;nbsp;are two linear transformations such that T&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;1&lt;/span&gt;T&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;is bejective.&amp;nbsp;&lt;/p&gt;

&lt;p&gt;Then T&lt;sub&gt;2&lt;/sub&gt; is one-one and T&lt;sub&gt;1&lt;/sub&gt; is on-to&lt;/p&gt;

&lt;p&gt;Then nullity(T&lt;sub&gt;2&lt;/sub&gt;) = 0&lt;/p&gt;

&lt;p&gt;So, by rank-nullity theorem, rank(T) = m&lt;/p&gt;

&lt;p&gt;Also,&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;T&lt;/span&gt;&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;1&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;is on-to and&amp;nbsp;T&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); position: relative; line-height: 0; vertical-align: baseline; bottom: -0.25em; font-size:10.5px;&quot;&gt;1&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;is a linear transformation from&amp;nbsp;ℝ&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); position: relative; line-height: 0; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;n&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;to ℝ&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41); position: relative; line-height: 0; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;m&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;.&lt;/span&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;Then&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;rank (T&lt;/span&gt;&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;1&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;) = m and rank (T&lt;/span&gt;&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; bottom: -0.25em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;​) = m&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Option (4) is true&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;u&gt;&lt;strong&gt;Explanation:&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;S = {T : ℝ&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&amp;nbsp;&lt;/span&gt;&amp;rarr; ℝ&lt;span style=&quot;position: relative;  line-height: 0; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;; T is a linear transformation with T(1, 0, 1) = (1, 2, 3) and T(1 ,2, 3) = (1, 0, 1)}&lt;/p&gt;

&lt;p&gt;(1, 0, 1) and (1, 2, 3) are linearly independent.&lt;/p&gt;

&lt;p&gt;Let basis of T be B = {(1, 0, 1), (1, 2, 3), (a, b, c)} where a, b, c are real numbers&lt;/p&gt;

&lt;p&gt;Then T(x, y, z) =&amp;nbsp;&amp;alpha;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(1, 0, 1) + &amp;beta;(1, 2, 3) + &amp;gamma;(a, b, c)&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;For different pair of&amp;nbsp;(a, b, c) we will get different T.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;Choice of&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;(a, b, c) is uncountable.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;Hence S is an uncountable set.&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Hence option (4) is true&lt;/strong&gt;&lt;/p&gt;
